import{_ as a,o as i,c as s,ag as l}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"페어링","description":"페어링 개요: DM 가능 사용자 승인 및 참여 가능 노드 관리","frontmatter":{"title":"페어링","description":"페어링 개요: DM 가능 사용자 승인 및 참여 가능 노드 관리"},"headers":[],"relativePath":"channels/pairing.md","filePath":"channels/pairing.md","lastUpdated":null}'),o={name:"channels/pairing.md"};function n(t,e,d,c,r,p){return i(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="페어링" tabindex="-1">페어링 <a class="header-anchor" href="#페어링" aria-label="Permalink to &quot;페어링&quot;">​</a></h1><p>&quot;페어링&quot;은 OpenClaw의 명시적인 <strong>소유자 승인</strong> 단계입니다. 두 가지 상황에서 사용됩니다:</p><ol><li><strong>DM 페어링</strong> (봇과 대화할 수 있는 사용자)</li><li><strong>노드 페어링</strong> (게이트웨이 네트워크에 참여 가능한 디바이스/노드)</li></ol><p>보안 컨텍스트: <a href="/openclaw-docs-ko/gateway/security/">보안</a></p><h2 id="_1-dm-페어링-인바운드-채팅-접근" tabindex="-1">1) DM 페어링 (인바운드 채팅 접근) <a class="header-anchor" href="#_1-dm-페어링-인바운드-채팅-접근" aria-label="Permalink to &quot;1) DM 페어링 (인바운드 채팅 접근)&quot;">​</a></h2><p>채널이 DM 정책 <code>pairing</code>으로 구성된 경우, 알 수 없는 발신자는 짧은 코드를 받고 승인될 때까지 메시지가 <strong>처리되지 않습니다</strong>.</p><p>기본 DM 정책은 다음에 문서화되어 있습니다: <a href="/openclaw-docs-ko/gateway/security/">보안</a></p><p>페어링 코드:</p><ul><li>8자, 대문자, 모호한 문자(<code>0O1I</code>) 없음.</li><li><strong>1시간 후 만료</strong>. 봇은 새 요청이 생성될 때만 페어링 메시지를 전송합니다(발신자당 약 1시간에 한 번).</li><li>대기 중인 DM 페어링 요청은 기본적으로 <strong>채널당 3개</strong>로 제한됩니다. 하나가 만료되거나 승인될 때까지 추가 요청은 무시됩니다.</li></ul><h3 id="발신자-승인" tabindex="-1">발신자 승인 <a class="header-anchor" href="#발신자-승인" aria-label="Permalink to &quot;발신자 승인&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>지원 채널: <code>bluebubbles</code>, <code>discord</code>, <code>feishu</code>, <code>googlechat</code>, <code>imessage</code>, <code>irc</code>, <code>line</code>, <code>matrix</code>, <code>mattermost</code>, <code>msteams</code>, <code>nextcloud-talk</code>, <code>nostr</code>, <code>openclaw-weixin</code>, <code>signal</code>, <code>slack</code>, <code>synology-chat</code>, <code>telegram</code>, <code>twitch</code>, <code>whatsapp</code>, <code>zalo</code>, <code>zalouser</code>.</p><h3 id="상태-저장-위치" tabindex="-1">상태 저장 위치 <a class="header-anchor" href="#상태-저장-위치" aria-label="Permalink to &quot;상태 저장 위치&quot;">​</a></h3><p><code>~/.openclaw/credentials/</code> 아래에 저장됩니다:</p><ul><li>대기 중인 요청: <code>&lt;channel&gt;-pairing.json</code></li><li>승인된 허용 목록 저장소: <ul><li>기본 계정: <code>&lt;channel&gt;-allowFrom.json</code></li><li>기본이 아닌 계정: <code>&lt;channel&gt;-&lt;accountId&gt;-allowFrom.json</code></li></ul></li></ul><p>계정 범위 지정 동작:</p><ul><li>기본이 아닌 계정은 범위가 지정된 허용 목록 파일만 읽기/쓰기합니다.</li><li>기본 계정은 채널 범위의 허용 목록 파일을 사용합니다.</li></ul><p>이 파일들은 어시스턴트 접근을 제어하므로 민감하게 취급하십시오.</p><p>중요: 이 저장소는 DM 접근용입니다. 그룹 인증은 별도입니다. DM 페어링 코드를 승인한다고 해서 해당 발신자가 그룹 명령을 실행하거나 그룹에서 봇을 제어할 수 있는 것은 아닙니다. 그룹 접근을 위해서는 채널의 명시적인 그룹 허용 목록(예: <code>groupAllowFrom</code>, <code>groups</code>, 또는 채널별 per-group/per-topic 오버라이드)을 구성하십시오.</p><h2 id="_2-노드-디바이스-페어링-ios-android-macos-헤드리스-노드" tabindex="-1">2) 노드 디바이스 페어링 (iOS/Android/macOS/헤드리스 노드) <a class="header-anchor" href="#_2-노드-디바이스-페어링-ios-android-macos-헤드리스-노드" aria-label="Permalink to &quot;2) 노드 디바이스 페어링 (iOS/Android/macOS/헤드리스 노드)&quot;">​</a></h2><p>노드는 <code>role: node</code>로 게이트웨이에 <strong>디바이스</strong>로 연결됩니다. 게이트웨이는 승인이 필요한 디바이스 페어링 요청을 생성합니다.</p><h3 id="telegram을-통한-페어링-ios에-권장" tabindex="-1">Telegram을 통한 페어링 (iOS에 권장) <a class="header-anchor" href="#telegram을-통한-페어링-ios에-권장" aria-label="Permalink to &quot;Telegram을 통한 페어링 (iOS에 권장)&quot;">​</a></h3><p><code>device-pair</code> 플러그인을 사용하면 Telegram에서 완전히 처음 디바이스 페어링을 할 수 있습니다:</p><ol><li>Telegram에서 봇에게 메시지 보내기: <code>/pair</code></li><li>봇이 두 개의 메시지로 응답합니다: 안내 메시지와 별도의 <strong>설정 코드</strong> 메시지(Telegram에서 복사/붙여넣기 용이).</li><li>휴대폰에서 OpenClaw iOS 앱 열기 → 설정 → 게이트웨이.</li><li>설정 코드를 붙여넣고 연결합니다.</li><li>Telegram으로 돌아가서: <code>/pair pending</code>(요청 ID, 역할, 범위 검토) 후 승인.</li></ol><p>설정 코드는 다음을 포함하는 base64로 인코딩된 JSON 페이로드입니다:</p><ul><li><code>url</code>: 게이트웨이 WebSocket URL (<code>ws://...</code> 또는 <code>wss://...</code>)</li><li><code>bootstrapToken</code>: 초기 페어링 핸드셰이크에 사용되는 단기 단일 디바이스 부트스트랩 토큰</li></ul><p>해당 부트스트랩 토큰에는 내장 페어링 부트스트랩 프로파일이 포함됩니다:</p><ul><li>기본 핸드오프 <code>node</code> 토큰은 <code>scopes: []</code> 유지</li><li>핸드오프 <code>operator</code> 토큰은 부트스트랩 허용 목록으로 제한: <code>operator.approvals</code>, <code>operator.read</code>, <code>operator.talk.secrets</code>, <code>operator.write</code></li><li>부트스트랩 범위 검사는 역할 접두사로 구분되며, 단일 플랫 범위 풀이 아닙니다: operator 범위 항목은 operator 요청만 충족하고, 비-operator 역할은 자체 역할 접두사 아래에서 범위를 요청해야 합니다</li></ul><p>설정 코드는 유효한 동안 비밀번호처럼 취급하십시오.</p><h3 id="노드-디바이스-승인" tabindex="-1">노드 디바이스 승인 <a class="header-anchor" href="#노드-디바이스-승인" aria-label="Permalink to &quot;노드 디바이스 승인&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reject</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>동일한 디바이스가 다른 인증 정보(예: 다른 역할/범위/공개 키)로 재시도하면 이전 대기 중인 요청이 대체되고 새 <code>requestId</code>가 생성됩니다.</p><h3 id="노드-페어링-상태-저장" tabindex="-1">노드 페어링 상태 저장 <a class="header-anchor" href="#노드-페어링-상태-저장" aria-label="Permalink to &quot;노드 페어링 상태 저장&quot;">​</a></h3><p><code>~/.openclaw/devices/</code> 아래에 저장됩니다:</p><ul><li><code>pending.json</code> (단기; 대기 중인 요청 만료)</li><li><code>paired.json</code> (페어링된 디바이스 + 토큰)</li></ul><h3 id="참고-사항" tabindex="-1">참고 사항 <a class="header-anchor" href="#참고-사항" aria-label="Permalink to &quot;참고 사항&quot;">​</a></h3><ul><li>레거시 <code>node.pair.*</code> API (CLI: <code>openclaw nodes pending|approve|reject|rename</code>)는 별도의 게이트웨이 소유 페어링 저장소입니다. WS 노드는 여전히 디바이스 페어링이 필요합니다.</li><li>페어링 레코드는 승인된 역할의 영구적인 진실의 원천입니다. 활성 디바이스 토큰은 해당 승인된 역할 집합으로 제한됩니다. 승인된 역할 외부의 스트레이 토큰 항목은 새로운 접근을 생성하지 않습니다.</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li>보안 모델 + 프롬프트 인젝션: <a href="/openclaw-docs-ko/gateway/security/">보안</a></li><li>안전하게 업데이트(doctor 실행): <a href="/openclaw-docs-ko/install/updating">업데이트</a></li><li>채널 구성: <ul><li>Telegram: <a href="/openclaw-docs-ko/channels/telegram">Telegram</a></li><li>WhatsApp: <a href="/openclaw-docs-ko/channels/whatsapp">WhatsApp</a></li><li>Signal: <a href="/openclaw-docs-ko/channels/signal">Signal</a></li><li>BlueBubbles (iMessage): <a href="/openclaw-docs-ko/channels/bluebubbles">BlueBubbles</a></li><li>iMessage (레거시): <a href="/openclaw-docs-ko/channels/imessage">iMessage</a></li><li>Discord: <a href="/openclaw-docs-ko/channels/discord">Discord</a></li><li>Slack: <a href="/openclaw-docs-ko/channels/slack">Slack</a></li></ul></li></ul>`,39)])])}const g=a(o,[["render",n]]);export{k as __pageData,g as default};
